con:config.con:script:
// ── Captura accessToken y refreshToken del response del Login ──
def response = context.expand('${01 - Login#Response}')

if (!response) {
    log.error "No hay respuesta del paso Login. Verifica que el servidor esté levantado."
    testRunner.fail("No hay respuesta del Login")
    return
}

def json
try {
    json = new groovy.json.JsonSlurper().parseText(response)
} catch (Exception e) {
    log.error "Error parseando JSON: " + e.message
    testRunner.fail("Respuesta no es JSON válido: " + response)
    return
}

def token   = json.accessToken
def refresh = json.refreshToken

if (!token) {
    log.error "No se encontró 'accessToken' en la respuesta: " + response
    testRunner.fail("Login fallido – revisa credenciales o el servidor")
    return
}

testRunner.testCase.testSuite.project.setPropertyValue("access_token",  token)
testRunner.testCase.testSuite.project.setPropertyValue("refresh_token", refresh ?: "")

log.info "✓ access_token  capturado: " + token.substring(0, Math.min(30, token.size())) + "..."
log.info "✓ refresh_token capturado: " + (refresh ? refresh.substring(0, Math.min(20, refresh.size())) + "..." : "(vacío)")
